        Api {
            state,
            ctx,
            props,
            send,
        }
    }

    fn on_props_changed(old: &Self::Props, new: &Self::Props) -> Vec<Self::Event> {
        if old.orientation == new.orientation && old.dir == new.dir && old.disabled == new.disabled
        {
            Vec::new()
        } else {
            alloc::vec![Event::SetProps { props: new.clone() }]
        }
    }
